import { useState, useMemo } from 'react';
import { View, Text } from 'react-native';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileTests } from './useKangurMobileTests';
import { KangurMobileScrollScreen } from '../shared/KangurMobileUi';
import { 
  SectionCard, 
  StatusPill, 
  ChoiceButton, 
  PrimaryButton, 
  TestPlayerResultsView, 
  TestExplanationView, 
  TestSuiteCard 
} from './tests-primitives';
import { 
    WARNING_TONE, 
    INDIGO_TONE, 
    BASE_TONE, 
    SUCCESS_TONE 
} from '../shared/KangurMobileUi';
import { 
    formatQuestionProgress, 
    formatPointsLabel, 
    resolveQuestionStatusTone 
} from '../scores/mobileScoreSummary';
import { type KangurTestSuiteItem, type KangurTestQuestion } from '@kangur/contracts/kangur-tests';

// Mock/Stub imports for missing test components
// ... (Imports)

function KangurMobileTestPlayer({
  item,
  onBackToCatalog,
}: {
  item: KangurTestSuiteItem;
  onBackToCatalog: () => void;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [currentIndex, setCurrentIndex] = useState(0);
  const [finished, setFinished] = useState(false);
  const [revealedAnswers, setRevealedAnswers] = useState<Record<string, boolean>>({});

  const questions = item.questions as KangurTestQuestion[];

  const scoreInfo = useMemo(() => {
      const score = questions.reduce((total, q) => answers[q.id] === q.correctChoiceLabel ? total + q.pointValue : total, 0);
      const maxScore = questions.reduce((total, q) => total + q.pointValue, 0);
      const scorePercent = maxScore > 0 ? Math.round((score / maxScore) * 100) : 0;
      return { score, maxScore, scorePercent };
  }, [questions, answers]);

  if (finished) {
    return (
      <TestPlayerResultsView
        score={scoreInfo.score}
        maxScore={scoreInfo.maxScore}
        scorePercent={scoreInfo.scorePercent}
        summaryTone={resolveQuestionStatusTone(scoreInfo.scorePercent)}
        onBackToCatalog={onBackToCatalog}
        copy={copy}
      />
    );
  }

  const currentQuestion = questions[currentIndex] ?? null;
  if (currentQuestion === null) {
      return <SectionCard title='Error'><Text>No question.</Text></SectionCard>;
  }

  return (
    <TestPlayerQuestionView
        currentQuestion={currentQuestion}
        currentIndex={currentIndex}
        totalQuestions={questions.length}
        locale={locale as 'de' | 'en' | 'pl'}
        copy={copy}
        answers={answers}
        setAnswers={setAnswers}
        revealedAnswers={revealedAnswers}
        setRevealedAnswers={setRevealedAnswers}
        setCurrentIndex={setCurrentIndex}
        setFinished={setFinished}
    />
  );
}

function QuestionChoices({
    currentQuestion,
    selectedLabel,
    showAnswer,
    handleSelect
}: {
    currentQuestion: KangurTestQuestion,
    selectedLabel: string | null,
    showAnswer: boolean,
    handleSelect: (label: string) => void
}): React.JSX.Element {
    return (
        <View style={{ gap: 10 }}>
            {currentQuestion.choices.map((choice) => (
                <ChoiceButton
                    choice={choice}
                    disabled={showAnswer}
                    isCorrect={choice.label === currentQuestion.correctChoiceLabel}
                    isRevealed={showAnswer}
                    isSelected={choice.label === selectedLabel}
                    key={choice.label}
                    label={choice.label}
                    onPress={() => handleSelect(choice.label)}
                />
            ))}
        </View>
    );
}

function TestControls({
    currentIndex,
    totalQuestions,
    isAnswered,
    showAnswer,
    handleReveal,
    handleNext,
    setCurrentIndex
}: {
    currentIndex: number,
    totalQuestions: number,
    isAnswered: boolean,
    showAnswer: boolean,
    handleReveal: () => void,
    handleNext: () => void,
    setCurrentIndex: React.Dispatch<React.SetStateAction<number>>
}): React.JSX.Element {
    return (
        <View style={{ gap: 10 }}>
            <PrimaryButton disabled={!isAnswered || showAnswer} label='Reveal' onPress={handleReveal} />
            <View style={{ flexDirection: 'row', gap: 10 }}>
                <PrimaryButton disabled={currentIndex === 0} label='Prev' onPress={() => setCurrentIndex((p) => p - 1)} tone={BASE_TONE} />
                <PrimaryButton disabled={!showAnswer} label='Next' onPress={handleNext} tone={SUCCESS_TONE} />
            </View>
        </View>
    );
}

interface TestPlayerQuestionViewProps {
    currentQuestion: KangurTestQuestion;
    currentIndex: number;
    totalQuestions: number;
    locale: 'de' | 'en' | 'pl';
    copy: (text: Record<string, string>) => string;
    answers: Record<string, string>;
    setAnswers: React.Dispatch<React.SetStateAction<Record<string, string>>>;
    revealedAnswers: Record<string, boolean>;
    setRevealedAnswers: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    setCurrentIndex: React.Dispatch<React.SetStateAction<number>>;
    setFinished: React.Dispatch<React.SetStateAction<boolean>>;
}

function TestPlayerQuestionView(props: TestPlayerQuestionViewProps): React.JSX.Element {
    const { 
        currentQuestion, currentIndex, totalQuestions, locale, copy, answers, 
        setAnswers, revealedAnswers, setRevealedAnswers, setCurrentIndex, setFinished 
    } = props;

    const selectedLabel = answers[currentQuestion.id] ?? null;
    const isAnswered = selectedLabel !== null;
    const showAnswer = Boolean(revealedAnswers[currentQuestion.id]);

    const handleSelect = (label: string): void => {
        if (!showAnswer) setAnswers((p) => ({ ...p, [currentQuestion.id]: label }));
    };

    const handleReveal = (): void => {
        if (isAnswered && !showAnswer) setRevealedAnswers((p) => ({ ...p, [currentQuestion.id]: true }));
    };

    const handleNext = (): void => {
        if (currentIndex < totalQuestions - 1) setCurrentIndex((p) => p + 1);
        else setFinished(true);
    };

    const selectedChoice = currentQuestion.choices.find((c) => c.label === selectedLabel) ?? null;
    const correctChoice = currentQuestion.choices.find((c) => c.label === currentQuestion.correctChoiceLabel) ?? null;

    return (
        <SectionCard title={formatQuestionProgress(currentIndex + 1, totalQuestions, locale)}>
            <View style={{ flexDirection: 'row', gap: 8 }}>
                <StatusPill label={formatPointsLabel(currentQuestion.pointValue, locale)} tone={WARNING_TONE} />
            </View>
            <Text style={{ fontSize: 16, fontWeight: '700' }}>{currentQuestion.prompt}</Text>

            <QuestionChoices 
                currentQuestion={currentQuestion} 
                selectedLabel={selectedLabel} 
                showAnswer={showAnswer} 
                handleSelect={handleSelect} 
            />

            {showAnswer && <TestExplanationView copy={copy} currentQuestion={currentQuestion} selectedChoice={selectedChoice} correctChoice={correctChoice} />}

            <TestControls 
                currentIndex={currentIndex} 
                totalQuestions={totalQuestions} 
                isAnswered={isAnswered} 
                showAnswer={showAnswer} 
                handleReveal={handleReveal} 
                handleNext={handleNext} 
                setCurrentIndex={setCurrentIndex} 
            />
        </SectionCard>
    );
}

export function KangurTestsScreen(): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();

  const { suites, isLoading, error, refresh } = useKangurMobileTests(null);
  const [activeSuiteId, setActiveSuiteId] = useState<string | null>(null);

  const activeSuite = activeSuiteId !== null ? suites.find((s) => s.suite.id === activeSuiteId) ?? null : null;

  if (activeSuite !== null) {
    return (
      <KangurMobileScrollScreen title={activeSuite.suite.title}>
        <KangurMobileTestPlayer item={activeSuite} onBackToCatalog={() => setActiveSuiteId(null)} />
      </KangurMobileScrollScreen>
    );
  }

  return (
    <KangurMobileScrollScreen onRefresh={async () => { await refresh(); }} refreshing={isLoading} title='Tests'>
      {isLoading && <Text>Loading...</Text>}
      {error !== null && <Text>{error}</Text>}
      {suites.map((item) => (
        <TestSuiteCard copy={copy} item={item} key={item.suite.id} locale={locale} onOpen={setActiveSuiteId} />
      ))}
    </KangurMobileScrollScreen>
  );
}

import { KANGUR_TEST_QUESTIONS_SETTING_KEY, KANGUR_TEST_SUITES_SETTING_KEY, kangurTestQuestionStoreSchema, kangurTestSuitesSchema, type KangurTestQuestion, type KangurTestQuestionStore, type KangurTestSuite } from '@kangur/contracts/kangur-tests';
import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type KangurLiteSettingRecord = {
  key: string;
  value: string;
};

export type KangurMobileTestSuiteItem = {
  questionCount: number;
  questions: KangurTestQuestion[];
  suite: KangurTestSuite;
};

type UseKangurMobileTestsResult = {
  error: string | null;
  focusToken: string | null;
  focusedSuiteId: string | null;
  isLoading: boolean;
  refresh: () => Promise<void>;
  suites: KangurMobileTestSuiteItem[];
};

const parseJsonValue = <T,>(
  raw: string | undefined,
  parser: {
    safeParse: (value: unknown) => { success: true; data: T } | { success: false };
  },
  fallback: T,
): T => {
  if (typeof raw !== 'string' || raw.trim().length === 0) {
    return fallback;
  }

  try {
    const parsed = parser.safeParse(JSON.parse(raw));
    return parsed.success ? parsed.data : fallback;
  } catch {
    return fallback;
  }
};

const isLiveSuite = (
  suite: Pick<KangurTestSuite, 'enabled' | 'publicationStatus'>,
): boolean => suite.enabled && suite.publicationStatus === 'live';

const isPublishedQuestion = (
  question: Pick<KangurTestQuestion, 'editorial'>,
): boolean => question.editorial.workflowStatus === 'published';

const getPublishedQuestionsForSuite = (
  questionStore: KangurTestQuestionStore,
  suiteId: string,
): KangurTestQuestion[] =>
  Object.values(questionStore)
    .filter(
      (question) => question.suiteId === suiteId && isPublishedQuestion(question),
    )
    .sort((left, right) => {
      const orderDelta = left.sortOrder - right.sortOrder;
      if (orderDelta !== 0) {
        return orderDelta;
      }

      return left.id.localeCompare(right.id);
    });

const resolveFocusedSuiteId = (
  focusToken: string,
  suites: KangurMobileTestSuiteItem[],
): string | null => {
  const normalized = focusToken.trim().toLowerCase();
  if (normalized === '') {
    return null;
  }

  const byId = suites.find((entry) => entry.suite.id.toLowerCase() === normalized);
  if (byId) {
    return byId.suite.id;
  }

  const byTitle = suites.find((entry) =>
    entry.suite.title.toLowerCase().includes(normalized),
  );
  if (byTitle) {
    return byTitle.suite.id;
  }

  const byCategory = suites.find((entry) =>
    entry.suite.category.toLowerCase().includes(normalized),
  );
  if (byCategory) {
    return byCategory.suite.id;
  }

  const byYear = suites.find(
    (entry) =>
      typeof entry.suite.year === 'number' &&
      String(entry.suite.year) === normalized,
  );
  if (byYear) {
    return byYear.suite.id;
  }

  return null;
};

export const useKangurMobileTests = (
  rawFocusToken: string | null,
): UseKangurMobileTestsResult => {
  const { apiBaseUrl } = useKangurMobileRuntime();
  const { copy } = useKangurMobileI18n();
  const focusToken = (rawFocusToken?.trim().toLowerCase()) ?? null;

  const settingsQuery = useQuery({
    queryKey: ['kangur-mobile', 'tests', 'lite-settings', apiBaseUrl],
    queryFn: async (): Promise<KangurLiteSettingRecord[]> => {
      const response = await fetch(`${apiBaseUrl}/api/settings/lite`, {
        cache: 'no-store',
        credentials: 'include',
      });
      if (!response.ok) throw new Error(`Failed to fetch lite settings (${response.status})`);
      const payload = await response.json();
      if (!Array.isArray(payload)) return [];

      return payload.filter(
        (entry: unknown): entry is KangurLiteSettingRecord =>
          typeof entry === 'object' && entry !== null && 'key' in entry && 'value' in entry
      ).map((entry: unknown) => {
          const item = entry as KangurLiteSettingRecord;
          return { key: String(item.key), value: String(item.value) };
      });
    },
    staleTime: 30_000,
  });

  const questionStore = useMemo(() => {
    const settingsByKey = new Map((settingsQuery.data ?? []).map((entry) => [entry.key, entry.value]));
    return parseJsonValue(settingsByKey.get(KANGUR_TEST_QUESTIONS_SETTING_KEY), kangurTestQuestionStoreSchema, {});
  }, [settingsQuery.data]);

  const suites = useMemo(() => getProcessedSuites(settingsQuery.data, questionStore), [settingsQuery.data, questionStore]);

  return {
    error: settingsQuery.error instanceof Error ? copy({ de: 'Die Tests konnten nicht geladen werden.', en: 'Could not load the tests.', pl: 'Nie udało się pobrać testów.' }) : null,
    focusToken,
    focusedSuiteId: focusToken !== null && suites.length > 0 ? resolveFocusedSuiteId(focusToken, suites) : null,
    isLoading: settingsQuery.isLoading,
    refresh: async () => { await settingsQuery.refetch(); },
    suites,
  };
};
